const _ = require("lodash");
const problemsData = require("../../data/problems.json");

/**
 * Filters problems by difficulty, tags, and limits the number of results.
 * Supports case-insensitive tag filtering with tags as comma-separated string or array.
 * Returns filtered problems and metadata including normalized tags.
 *
 * @param {Object} params
 * @param {string|Array<string>} [params.tags] - Tags to filter by (case-insensitive).
 * @param {string} [params.difficulty] - Difficulty filter (e.g., 'easy', 'medium', 'hard').
 * @param {number} [params.limit] - Maximum number of problems to return.
 * @returns {Object} - { problems: Array, metadata: { tags: Array<string> } }
 */
function getProblems({ tags, difficulty, limit } = {}) {
  let filtered = problemsData;

  // Normalize and parse tags filter
  let normalizedTags = [];
  if (tags) {
    if (typeof tags === "string") {
      // Split comma-separated string and trim
      normalizedTags = tags
        .split(",")
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    } else if (Array.isArray(tags)) {
      normalizedTags = tags
        .map(t => (typeof t === "string" ? t.trim().toLowerCase() : ""))
        .filter(t => t.length > 0);
    }
  }

  // Filter by difficulty if provided
  if (difficulty) {
    const diffLower = difficulty.toLowerCase();
    filtered = filtered.filter(p => p.difficulty && p.difficulty.toLowerCase() === diffLower);
  }

  // Filter by tags if provided
  if (normalizedTags.length > 0) {
    filtered = filtered.filter(problem => {
      if (!problem.tags || !Array.isArray(problem.tags)) return false;
      const problemTagsLower = problem.tags.map(t => t.toLowerCase());
      // Problem must have all tags in normalizedTags
      return normalizedTags.every(tag => problemTagsLower.includes(tag));
    });
  }

  // Stable sort by problem id ascending
  filtered = _.sortBy(filtered, ["id"]);

  // Apply limit if provided
  if (typeof limit === "number" && limit >= 0) {
    filtered = filtered.slice(0, limit);
  }

  return {
    problems: filtered,
    metadata: {
      tags: normalizedTags
    }
  };
}

module.exports = {
  getProblems
};
